import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import axios from 'axios';

const ProductDetails = () => {
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const { id } = useParams();

  useEffect(() => {
    fetchProduct();
  }, [id]);

  const fetchProduct = async () => {
    try {
      setLoading(true);
      const response = await axios.get(`/api/products/${id}`);
      setProduct(response.data.product);
      setError('');
    } catch (err) {
      setError('Failed to fetch product details');
      console.error('Error fetching product:', err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="loading">Loading product details...</div>;
  }

  if (error || !product) {
    return (
      <div className="container">
        <div className="error">{error || 'Product not found'}</div>
        <Link to="/" className="btn btn-primary mt-20">Back to Products</Link>
      </div>
    );
  }

  return (
    <div className="container dark:bg-gray-950 transition-colors duration-300">
      <div className="product-detail-container">
        <Link to="/" className="btn btn-secondary mb-20 dark:bg-gray-800 dark:hover:bg-gray-700">← Back to Products</Link>

        <div className="product-detail-card dark:bg-gray-900 dark:border-gray-800">
          <div className="product-detail-image dark:bg-gray-800">
            <img 
              src={product.image} 
              alt={product.name}
              className="product-detail-img"
            />
          </div>

          <div className="product-detail-info">
            <h1 className="product-detail-name dark:text-gray-100">{product.name}</h1>

            <div className="product-detail-price dark:text-green-400">
              ${product.price.toFixed(2)}
            </div>

            <div className="product-detail-category">
              <span className="category-badge dark:bg-gray-700 dark:text-gray-300">
                {product.category.charAt(0).toUpperCase() + product.category.slice(1)}
              </span>
              {product.inStock ? (
                <span className="stock-badge in-stock dark:bg-green-900/40 dark:text-green-300">In Stock</span>
              ) : (
                <span className="stock-badge out-of-stock dark:bg-red-900/40 dark:text-red-300">Out of Stock</span>
              )}
            </div>

            <div className="product-detail-description">
              <h3 className="dark:text-gray-200">Description</h3>
              <p className="dark:text-gray-400">{product.description}</p>
            </div>

            <div className="product-detail-actions mt-30">
              <h3 className="mb-10 dark:text-gray-200">Interested in this product?</h3>
              <p className="mb-20 text-gray-600 dark:text-gray-400">Contact us to place an order or for more information:</p>

              <div className="flex flex-col gap-3">
                <a 
                  href={`https://wa.me/9841000000?text=Hi, I am interested in ${product.name}`} 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="btn btn-whatsapp flex items-center justify-center gap-2"
                >
                  <span className="icon">📱</span> Contact via WhatsApp
                </a>

                <a 
                  href={`mailto:halesiharbal@gmail.com?subject=Inquiry about ${product.name}&body=Hi, I am interested in ${product.name}. Please provide more details.`}
                  className="btn btn-gmail flex items-center justify-center gap-2"
                >
                  <span className="icon">📧</span> Contact via Gmail
                </a>

                <div className="flex gap-3 mt-2">
                  <a 
                    href="https://facebook.com/halesiharbal" 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="btn btn-facebook flex-1 text-center"
                  >
                    Facebook
                  </a>
                  <a 
                    href="https://instagram.com/halesiharbal" 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="btn btn-instagram flex-1 text-center"
                  >
                    Instagram
                  </a>
                </div>
              </div>
            </div>

            <div className="product-detail-meta">
              <p><strong>Product ID:</strong> {product._id}</p>
              <p><strong>Added on:</strong> {new Date(product.createdAt).toLocaleDateString()}</p>
              {product.updatedAt !== product.createdAt && (
                <p><strong>Last updated:</strong> {new Date(product.updatedAt).toLocaleDateString()}</p>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductDetails;
